solution: class Solution {
public:
    int maxVowels(string s, int k) {
        int n = s.size();
        int cnt = 0, maxCnt = 0;
        auto isVowel = [](char c) {
            return c=='a'||c=='e'||c=='i'||c=='o'||c=='u';
        };
        for (int i = 0; i < n; ++i) {
            if (isVowel(s[i])) ++cnt;
            if (i >= k && isVowel(s[i-k])) --cnt;
            maxCnt = max(maxCnt, cnt);
        }
        return maxCnt;
    }
};
